  feeds = {};
  vi.mocked(fetchWithAuth).mockImplementation(async (url: string) => {
    const xml = feeds[url];
    if (!xml) {
      return {
        ok: false,
        url,
        status: 404,
        statusText: 'Not Found',
        text: async () => '',
      } as unknown as Response;
    }
    return {
      ok: true,
      url,
      status: 200,
      statusText: 'OK',
      text: async () => xml,
    } as unknown as Response;
  });
})

